### Generic Functions

Generics allow creating functions that work with any type while preserving type information.

### Basic Syntax

```typescript
function identity<T>(arg: T): T {
  return arg;
}

let result1 = identity<string>("hello"); // type: string
let result2 = identity(42); // type: number (inferred)
```

### Type Parameters

```typescript
// Single type parameter
function firstElement<T>(arr: T[]): T | undefined {
  return arr[0];
}

// Multiple type parameters
function pair<T, U>(first: T, second: U): [T, U] {
  return [first, second];
}

let result = pair("hello", 42); // type: [string, number]
```

### Generic Constraints

```typescript
interface HasLength {
  length: number;
}

function logLength<T extends HasLength>(arg: T): T {
  console.log(arg.length);
  return arg;
}

logLength("hello"); // OK, string has length
logLength([1, 2, 3]); // OK, array has length
// logLength(123); // Error: number doesn't have length
```

### Generic Defaults

```typescript
function createArray<T = string>(length: number, value: T): T[] {
  return Array(length).fill(value);
}

let arr = createArray(3, "a"); // type: string[]
```

### Generic Inference

TypeScript often infers generic types from arguments:

```typescript
function merge<T, U>(obj1: T, obj2: U): T & U {
  return { ...obj1, ...obj2 };
}

let merged = merge({ name: "Alice" }, { age: 30 });
// type: { name: string } & { age: number }
```

> **Key Point:** Generics provide type safety without sacrificing flexibility.

codeExample:
// Identity function
function wrap<T>(value: T): { value: T } {
  return { value };
}

const wrapped = wrap(42); // type: { value: number }

// Generic array functions
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

const user = { name: "Alice", age: 30 };
const name = getProperty(user, "name"); // type: string

// Generic with callback
function map<T, U>(arr: T[], fn: (item: T) => U): U[] {
  return arr.map(fn);
}

const lengths = map(["a", "bb", "ccc"], (s) => s.length);
